  bucket_id = 'property-images' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL)
);
DROP POLICY IF EXISTS "Public can view property images" ON storage.objects;
CREATE POLICY "Public can view property images" ON storage.objects FOR SELECT TO public USING (bucket_id = 'property-images');
DROP POLICY IF EXISTS "Users can update their own property images" ON storage.objects;
CREATE POLICY "Users can update their own property images" ON storage.objects FOR UPDATE TO authenticated USING (
  bucket_id = 'property-images' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL)
) WITH CHECK (bucket_id = 'property-images' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL));
DROP POLICY IF EXISTS "Users can delete their own property images" ON storage.objects;
CREATE POLICY "Users can delete their own property images" ON storage.objects FOR DELETE TO authenticated USING (
  bucket_id = 'property-images' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL)
);

DROP POLICY IF EXISTS "Public can view registration documents" ON storage.objects;
CREATE POLICY "Public can view registration documents" ON storage.objects FOR SELECT TO public USING (bucket_id = 'registration-documents');
DROP POLICY IF EXISTS "Users can upload registration documents" ON storage.objects;
CREATE POLICY "Users can upload registration documents" ON storage.objects FOR INSERT TO authenticated WITH CHECK (
  bucket_id = 'registration-documents' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL)
