DROP POLICY IF EXISTS "Users can update registration documents" ON storage.objects;
CREATE POLICY "Users can update registration documents" ON storage.objects FOR UPDATE TO authenticated USING (
  bucket_id = 'registration-documents' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL)
) WITH CHECK (bucket_id = 'registration-documents' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL));
DROP POLICY IF EXISTS "Users can delete registration documents" ON storage.objects;
CREATE POLICY "Users can delete registration documents" ON storage.objects FOR DELETE TO authenticated USING (
  bucket_id = 'registration-documents' AND (current_setting('request.jwt.claims', true) IS NOT NULL OR auth.uid() IS NOT NULL)
);
